        if lhs.negotiatedProtocol != rhs.negotiatedProtocol {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(status)
        hasher.combine(headers)
        hasher.combine(body)
        hasher.combine(negotiatedProtocol)
    }
}



