/**
 * What the client does on a 3xx. The reqwest default (10 unbounded
 * redirects) is too permissive for a security-sensitive client. Variants
 * are struct-style (the `{}`) to preserve the generated binding shape.
 * `NoRedirects` (not `None`) avoids colliding with `Option::None` in matches.
 */

public enum RedirectPolicy {
    
    case noRedirects
    case sameOriginOnly
    case limited(max: UInt8
    )
}


#if compiler(>=6)
extension RedirectPolicy: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeRedirectPolicy: FfiConverterRustBuffer {
    typealias SwiftType = RedirectPolicy

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> RedirectPolicy {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .noRedirects
        
        case 2: return .sameOriginOnly
        
        case 3: return .limited(max: try FfiConverterUInt8.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: RedirectPolicy, into buf: inout [UInt8]) {
        switch value {
        
        
        case .noRedirects:
            writeInt(&buf, Int32(1))
        
        
        case .sameOriginOnly:
            writeInt(&buf, Int32(2))
        
        
        case let .limited(max):
            writeInt(&buf, Int32(3))
            FfiConverterUInt8.write(max, into: &buf)
            
        }
    }
}


